create table roma_main.ftth_produkte_gk (
    fpgk_id            number(38, 0)
        generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 start with 1 cache 20
        noorder nocycle nokeep noscale
    not null enable,
    fpgk_key           varchar2(4 char),
    fpgk_status        varchar2(4000 char),
    fpgk_template_id   varchar2(4000 char),
    fpgk_produktname   varchar2(4000 char),
    fpgk_access_type   varchar2(4000 char),
